object_location:
@phdthesis{Bulbul2025,
  title = {Ahmed Vâsıf Efendi ve Mehâsinü'l-Âsâr ve Hakā'iku'l-Ahbâr'ı 1203-1209/1789-1794 (İnceleme ve Metin)},
  author = {Yavuz Bülbül},
  school = {Marmara Üniversitesi Sosyal Bilimler Enstitüsü},
  year = {2025},
  address = {İstanbul},
  note = {İslam Tarihi ve Sanatları Ana Bilim Dalı, İslam Tarihi Bilim Dalı. Advisor: Prof. Dr. Hüseyin Sarıkaya. Doktora Tezi.},
  abstract = {Bu çalışma, 18. yüzyıl Osmanlı tarihçiliğinin önde gelen isimlerinden Ahmed Vâsıf Efendi’nin hayatı, idari ve diplomatik kariyeri, telif faaliyetleri ve tarihçilik anlayışını çok yönlü biçimde incelemektedir. Birinci bölümde, Vâsıf Efendi’nin erken yaşamı, Osmanlı-Rus ve Osmanlı-Avusturya savaşlarındaki rolleri, tarihçi, diplomat, bürokrat ve matbaacı kimliği ele alınarak Osmanlı bürokrasisindeki çok katmanlı görevleri analiz edilmiştir. İkinci bölüm, Vâsıf’ın edebiyat, ahlak, coğrafya ve tarih alanlarındaki te’lîfâtını ve bu eserlerin Osmanlı ilim ve kültür çevrelerindeki yerini incelemektedir. Üçüncü bölüm, onun başyapıtı olan Mehâsinü'l-Âsâr ve Hakā’iku'l-Ahbâr’ı merkeze alarak eserin muhtevası, nüshaları, kaynakları ve Osmanlı tarih yazımına etkilerini detaylandırmakta ve özellikle hicrî 1203–1209 (miladî 1789–1794) arasındaki olayları ihtiva eden dönem üzerinde yoğunlaşmaktadır. Çalışmada ayrıca Vâsıf’ın kullandığı resmi belgeler, telhisler, hatt-ı hümâyûnlar, anlaşma metinleri ve duyum/müşahede kayıtları incelenmiş; Enverî ve Edîb gibi çağdaş kronikçilerle yaptığı metin aktarımları mukayeseli olarak ele alınmıştır. Eserin Ahmed Cevdet Paşa gibi sonraki müverrihler üzerindeki etkisi ve Osmanlı tarihçiliği içindeki konumu tartışılmıştır. Bu tez, Ahmed Vâsıf Efendi’nin yalnızca bir tarihçi değil, aynı zamanda Osmanlı modernleşme sürecinin entelektüel ve siyasi figürlerinden biri olduğunu ortaya koymayı amaçlamaktadır.}
}

